namespace BloodAndBittersteel.Features.IronbornWives
{
    public static class IronbornWivesDialogs
    {
        public const string StartDialogNeutral = "{=bab_ironborn_wife_start_neutral}You are my prisoner, taken by the iron price. I claim you as my salt wife under the Drowned God’s eyes. What is dead may never die.";
        public const string StartDialogDevious = "{=bab_ironborn_wife_start_devious}Submit quietly and become my salt wife. I’ll spare what’s left of your kin and let your name live on under my banner. Refuse, and the sea takes everything.";
        public const string StartDialogImpulsive = "{=bab_ironborn_wife_start_impulsive}By the sea and salt! I see what I want and I take it. You’re mine now my salt wife, and damn the consequences! What is dead may never die!";
        public const string StartDialogSadistic = "{=bab_ironborn_wife_start_sadistic}Look at you trembling... it pleases me. You’ll be my salt wife, broken and begging at my feet every night while the Drowned God laughs.";
        public const string StartDialogMerciful = "{=bab_ironborn_wife_start_merciful}You’ve endured enough in this raid. Swear yourself to me as salt wife and I will show mercy. No thrall’s collar for you, only my protection and my name.";
        public const string StartDialogCalculating = "{=bab_ironborn_wife_start_calculating}Your house is broken, your lands are mine. Become my salt wife and your noble blood continues under Ironborn rule. It is the only path that does not end in the sea.";

        public const string LowNobleNonFighterAgree = "{=bab_ironborn_wife_agree_non_fighter_low}Please, my lord… I have no great name or strong kin left. If swearing myself to you as salt wife spares my life and what remains of my family, then I yield. I accept.";
        public const string HighNobleNonFighterAgree = "{=bab_ironborn_wife_agree_non_fighter_high}My lands are yours and my banners are ash. If becoming your salt wife is the only path left, then… I accept. The Seven forgive me.";
        public const string NobleFighterAgree = "{=bab_ironborn_wife_agree_fighter}I fought beside my father’s men and still I stand. But if becoming your salt wife keeps the rest of my blood alive, then curse your Drowned God—I accept.";

        public const string LowNobleNonFighterRefuse = "{=bab_ironborn_wife_refuse_non_fighter_low}I will not become your salt wife, reaver. Do what you will with me. Kill me if you must—I accept whatever fate the Seven decree.";
        public const string HighNobleNonFighterRefuse = "{=bab_ironborn_wife_refuse_non_fighter_high}How dare you, you filthy reaver! I am highborn, kin to kings. The Seven Kingdoms will not abide this outrage. My house will burn your islands for this insult.";
        public const string NobleFighterRefuse = "{=bab_ironborn_wife_refuse_fighter}I would rather you cut my throat right now than call me salt wife. Kill me, I choose an honorable death over your chains.";

        public const string ExecutionSadistic = "{=bab_ironborn_wife_execution_sadistic}You chose death over my bed? How delightful. I will make it slow so the Drowned God can hear every scream. Die well, little southron.";
        public const string ExecutionDevious = "{=bab_ironborn_wife_execution_devious}You refused me, so now your pretty head will decorate my prow. The other captives will learn quickly what happens to those who say no.";
        public const string ExecutionImpulsive = "{=bab_ironborn_wife_execution_impulsive}Bah! Then die, you stubborn bitch! I offered you salt and sea and you spit in my face. Overboard now!";
        public const string ExecutionNeutral = "{=bab_ironborn_wife_execution_neutral}You chose death. So be it. The iron price demands payment one way or another. Throw her over.";

        public const string SpareNeutral = "{=bab_ironborn_wife_spare_neutral}I offered you life as my salt wife. You refused. Very well, you are no longer worth the trouble. Take her below as a thrall and be done with it.";
        public const string SpareMerciful = "{=bab_ironborn_wife_spare_merciful}I offered mercy once and you threw it back in my face. Still, I will not kill you. Bind her and let her live. That is more kindness than most reavers give.";
        public const string SpareCalculating = "{=bab_ironborn_wife_spare_calculating}Killing you now is wasteful. Your blood and name may yet buy me something in the future. Collar her. She lives.";

        public const string ConfirmationNeutral = "{=bab_ironborn_wife_confirmation_neutral}The Drowned God has heard and accepted the claim. You are no longer a prisoner, you are now my salt wife. Rise.";
        public const string ConfirmationDevious = "{=bab_ironborn_wife_confirmation_devious}Your tongue may still rebel, but your body and name are already mine. The Drowned God laughs at your resistance. Stand, salt wife.";
        public const string RetractionNeutral = "{=bab_ironborn_wife_retraction_neutral}No, you do not please me after all. Thrall’s collar for you. The sea takes what I do not want.";
    }
}
